// High-compatibility HTML5 Audio & Web Audio Synthesizer with Haptic Vibration

const WAITER_CHIME_B64 = "data:audio/wav;base64,";
const KITCHEN_CHIME_B64 = "data:audio/wav;base64,";

let waiterAudio: HTMLAudioElement | null = null;
let kitchenAudio: HTMLAudioElement | null = null;
let isAudioUnlocked = false;

function getWaiterAudio(): HTMLAudioElement | null {
  if (typeof window === "undefined") return null;
  if (!waiterAudio) {
    waiterAudio = new Audio(WAITER_CHIME_B64);
    waiterAudio.preload = "auto";
  }
  return waiterAudio;
}

function getKitchenAudio(): HTMLAudioElement | null {
  if (typeof window === "undefined") return null;
  if (!kitchenAudio) {
    kitchenAudio = new Audio(KITCHEN_CHIME_B64);
    kitchenAudio.preload = "auto";
  }
  return kitchenAudio;
}

// Unlock HTML5 Audio on first user gesture (required for iOS Safari & Android Chrome)
export function setupAudioUnlock() {
  if (typeof window === "undefined" || isAudioUnlocked) return;

  const unlock = () => {
    const wAudio = getWaiterAudio();
    const kAudio = getKitchenAudio();

    if (wAudio) {
      wAudio.play().then(() => {
        wAudio.pause();
        wAudio.currentTime = 0;
        isAudioUnlocked = true;
      }).catch(() => {});
    }

    if (kAudio) {
      kAudio.play().then(() => {
        kAudio.pause();
        kAudio.currentTime = 0;
        isAudioUnlocked = true;
      }).catch(() => {});
    }

    window.removeEventListener("pointerdown", unlock);
    window.removeEventListener("touchstart", unlock);
    window.removeEventListener("click", unlock);
    window.removeEventListener("keydown", unlock);
  };

  window.addEventListener("pointerdown", unlock, { once: true });
  window.addEventListener("touchstart", unlock, { once: true });
  window.addEventListener("click", unlock, { once: true });
  window.addEventListener("keydown", unlock, { once: true });
}

// Play waiter call chime & vibrate (Celulares, Tablets, PC)
export function playWaiterCallSound() {
  setupAudioUnlock();

  // Haptic vibration for mobile phones
  if (typeof navigator !== "undefined" && typeof navigator.vibrate === "function") {
    try {
      navigator.vibrate([300, 150, 300]);
    } catch (e) {
      // Ignore restriction
    }
  }

  const audio = getWaiterAudio();
  if (audio) {
    audio.currentTime = 0;
    audio.play().catch(err => console.warn("Audio play blocked by browser:", err));
  }
}

// Play kitchen alert chime for new orders (TV / Cocina)
export function playKitchenNewOrderSound() {
  setupAudioUnlock();

  const audio = getKitchenAudio();
  if (audio) {
    audio.currentTime = 0;
    audio.play().catch(err => console.warn("Kitchen audio play blocked by browser:", err));
  }
}
